import logging
import pandas as pd

# Configurar logging
logging.basicConfig(level=logging.INFO)

def procesar_datos_gps(archivo):
    try:
        datos = pd.read_csv(archivo)
        logging.info(f"Procesados {len(datos)} puntos GPS")
        return datos
    except FileNotFoundError:
        logging.error(f"Archivo {archivo} no encontrado")
        return None
    except Exception as e:
        logging.error(f"Error inesperado: {e}")
        return None


library(tryCatch)
library(futile.logger)

# Configurar logging
flog.threshold(INFO)

procesar_datos_gps &lt;- function(archivo) {
  tryCatch({
    datos &lt;- read.csv(archivo)
    flog.info("Procesados %s puntos GPS", nrow(datos))
    return(datos)
  }, error = function(e) {
    flog.error("Error al procesar %s: %s", archivo, e$message)
    return(NULL)
  })
}

